// Express application with security best practices and error handling
// Includes input validation, security headers, and comprehensive error handling

const express = require('express');
const helmet = require('helmet');
const compression = require('compression');
const rateLimit = require('express-rate-limit');

const app = express();
const PORT = process.env.PORT || 3000;

// ============================================================================
// SECURITY & MIDDLEWARE
// ============================================================================

// Security headers protection
app.use(helmet());

// Response compression (gzip/brotli)
app.use(compression());

// Rate limiting to prevent abuse
const limiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100, // limit each IP to 100 requests per windowMs
  message: 'Too many requests from this IP, please try again later.',
  standardHeaders: true,
  legacyHeaders: false,
});
app.use(limiter);

// Request body parsing with size limits
app.use(express.json({ limit: '10kb' }));
app.use(express.urlencoded({ limit: '10kb', extended: false }));

// ============================================================================
// MIDDLEWARE: REQUEST LOGGING
// ============================================================================

// Simple request logging middleware
app.use((req, res, next) => {
  const start = Date.now();
  res.on('finish', () => {
    const duration = Date.now() - start;
    console.log(`[${new Date().toISOString()}] ${req.method} ${req.path} - ${res.statusCode} - ${duration}ms`);
  });
  next();
});

// ============================================================================
// UTILITY FUNCTIONS
// ============================================================================

// Standardized success response wrapper
const sendSuccess = (res, data, statusCode = 200) => {
  res.status(statusCode).json({
    success: true,
    data,
    timestamp: new Date().toISOString(),
  });
};

// Pre-serialized static user data (optimization for high-traffic scenarios)
const USERS_DATA = [
  { id: 1, name: 'Alice', email: 'alice@example.com' },
  { id: 2, name: 'Bob', email: 'bob@example.com' },
];

// ============================================================================
// ROUTES
// ============================================================================

// Health check endpoint
app.get('/health', (req, res) => {
  // Cache health check for 10 seconds to reduce timestamp generation overhead
  res.set('Cache-Control', 'public, max-age=10');
  sendSuccess(res, { status: 'ok' });
});

// Get all users endpoint
app.get('/users', (req, res) => {
  // Query parameter validation (optional: filter by name)
  const { name } = req.query;

  let users = USERS_DATA;

  // Optional filtering by name (case-insensitive)
  if (name && typeof name === 'string') {
    const searchTerm = name.toLowerCase().trim();
    if (searchTerm.length > 50) {
      return res.status(400).json({
        success: false,
        error: 'Search term too long (max 50 characters)',
      });
    }
    users = users.filter((user) =>
      user.name.toLowerCase().includes(searchTerm)
    );
  }

  // Cache static user data for 1 hour
  res.set('Cache-Control', 'public, max-age=3600');
  sendSuccess(res, users);
});

// ============================================================================
// ERROR HANDLING
// ============================================================================

// 404 Not Found handler
app.use((req, res) => {
  res.status(404).json({
    success: false,
    error: 'Not Found',
    path: req.path,
  });
});

// Global error handling middleware (must be last)
app.use((err, req, res, next) => {
  console.error('[ERROR]', {
    timestamp: new Date().toISOString(),
    message: err.message,
    stack: process.env.NODE_ENV === 'development' ? err.stack : undefined,
    path: req.path,
    method: req.method,
  });

  const statusCode = err.statusCode || err.status || 500;
  res.status(statusCode).json({
    success: false,
    error: process.env.NODE_ENV === 'production'
      ? 'Internal Server Error'
      : err.message,
  });
});

// ============================================================================
// SERVER STARTUP
// ============================================================================

// Only start server if this is the main module (not imported)
if (require.main === module) {
  const server = app.listen(PORT, (err) => {
    if (err) {
      console.error('[STARTUP ERROR]', err);
      process.exit(1);
    }
    console.log(`[${new Date().toISOString()}] Server running on port ${PORT}`);
    console.log(`Environment: ${process.env.NODE_ENV || 'development'}`);
  });

  // Configure keep-alive timeout
  server.keepAliveTimeout = 65000;

  // Graceful shutdown handler
  process.on('SIGTERM', () => {
    console.log('[SHUTDOWN] SIGTERM received, shutting down gracefully...');
    server.close(() => {
      console.log('[SHUTDOWN] Server closed');
      process.exit(0);
    });
  });

  // Handle uncaught exceptions
  process.on('uncaughtException', (err) => {
    console.error('[UNCAUGHT EXCEPTION]', err);
    process.exit(1);
  });

  // Handle unhandled promise rejections
  process.on('unhandledRejection', (reason, promise) => {
    console.error('[UNHANDLED REJECTION]', { reason, promise });
    process.exit(1);
  });
}

module.exports = app;

